contracts/Escrow.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "@chainlink/contracts/src/v0.8/automation/AutomationCompatible.sol";

interface IPropertyToken {
    function mintTokens(uint256 propertyId, address buyer, uint256 amount) external;
    function getCurrentPrice(uint256 propertyId) external view returns (uint256);
    function getProperty(uint256 propertyId) external view returns (
        uint256 id,
        string memory name,
        string memory uri,
        uint256 totalSupply,
        uint256 mintedSupply,
        uint256 fundingTarget,
        uint256 fundingDeadline,
        uint8 currentPhase,
        bool isActive,
        bool isFunded
    );
    function markFunded(uint256 propertyId) external;
    function burnFromOnFailure(uint256 propertyId, address holder, uint256 amount) external;
    function balanceOf(address account, uint256 id) external view returns (uint256);
}

/**
 * @title RevitaHub Escrow
 * @notice Handles token purchases, 100% funding requirement, and 3% APR refunds
 * @dev Integrates with Chainlink Automation for deadline monitoring
 */
contract Escrow is AccessControl, ReentrancyGuard, Pausable, AutomationCompatibleInterface {
    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");

    // 3% APR for refunds (in basis points)
    uint256 public constant REFUND_APR = 300;
    uint256 public constant BASIS_POINTS = 10000;
    uint256 public constant SECONDS_PER_YEAR = 365 days;

    IPropertyToken public propertyToken;

    // Purchase record
    struct Purchase {
        address buyer;
        uint256 propertyId;
        uint256 amount;
        uint256 price;
        uint256 totalPaid;
        uint256 timestamp;
        bool refunded;
    }

    // Property escrow state
    struct PropertyEscrow {
        uint256 totalRaised;
        uint256 fundingTarget;
        uint256 deadline;
        bool isComplete;
        bool refundsProcessed;
    }

    // Storage
    mapping(uint256 => Purchase[]) public propertyPurchases;
    mapping(uint256 => PropertyEscrow) public propertyEscrows;
    mapping(uint256 => mapping(address => uint256)) public buyerContributions;

    // All property IDs for automation
    uint256[] public activeProperties;
    mapping(uint256 => bool) public isPropertyActive;

    // Dynamic funding targets based on poll demand
    mapping(uint256 => uint256) public pollDemandScores; // Poll demand in basis points (e.g., 8000 = 80% support)
    mapping(uint256 => uint256) public baseFundingTargets; // Original funding target before adjustment
    uint256 public constant MAX_DEMAND_BONUS = 2500; // Max 25% increase for high-demand properties

    // Events
    event PurchaseReceived(
        uint256 indexed propertyId,
        address indexed buyer,
        uint256 amount,
        uint256 totalPaid,
        uint256 timestamp
    );
    event FundingComplete(uint256 indexed propertyId, uint256 totalRaised);
    event RefundProcessed(
        uint256 indexed propertyId,
        address indexed buyer,
        uint256 principal,
        uint256 interest,
        uint256 total
    );
    event FundingFailed(uint256 indexed propertyId, uint256 totalRaised, uint256 target);
    event FundsReleased(uint256 indexed propertyId, address indexed recipient, uint256 amount);

    // Regulatory Compliance Events
    event CompliancePurchaseRecorded(
        uint256 indexed propertyId,
        address indexed buyer,
        uint256 amount,
        uint256 totalPaid,
        bytes32 transactionHash
    );
    event InvestorLimitChecked(
        uint256 indexed propertyId,
        address indexed investor,
        uint256 currentContribution,
        uint256 newContribution,
        bool withinLimit
    );
    event SuspiciousActivityReported(
        uint256 indexed propertyId,
        address indexed account,
        string activityType,
        uint256 timestamp
    );
    event RefundComplianceRecorded(
        uint256 indexed propertyId,
        address indexed recipient,
        uint256 principal,
        uint256 interest,
        uint256 timestamp
    );
    event PollDemandUpdated(
        uint256 indexed propertyId,
        uint256 demandScore,
        uint256 adjustedTarget
    );

    constructor(address _propertyToken) {
        propertyToken = IPropertyToken(_propertyToken);
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(OPERATOR_ROLE, msg.sender);
    }

    /**
     * @notice Initialize escrow for a property
     * @param propertyId Property ID
     * @param fundingTarget Required funding amount
     * @param deadline Funding deadline timestamp
     */
    function initializeEscrow(
        uint256 propertyId,
        uint256 fundingTarget,
        uint256 deadline
    ) external onlyRole(OPERATOR_ROLE) {
        require(!isPropertyActive[propertyId], "Escrow already exists");

        // Store base target for potential dynamic adjustment
        baseFundingTargets[propertyId] = fundingTarget;

        propertyEscrows[propertyId] = PropertyEscrow({
            totalRaised: 0,
            fundingTarget: fundingTarget,
            deadline: deadline,
            isComplete: false,
            refundsProcessed: false
        });

        activeProperties.push(propertyId);
        isPropertyActive[propertyId] = true;
    }

    /**
     * @notice Update poll demand score and adjust funding target dynamically
     * @dev Higher demand = higher funding target (premium for popular properties)
     * @param propertyId Property ID
     * @param demandScore Poll support percentage in basis points (e.g., 8000 = 80%)
     */
    function updatePollDemand(uint256 propertyId, uint256 demandScore) external onlyRole(OPERATOR_ROLE) {
        require(isPropertyActive[propertyId], "Property not active");
        require(demandScore <= 10000, "Invalid demand score");

        PropertyEscrow storage escrow = propertyEscrows[propertyId];
        require(!escrow.isComplete, "Funding already complete");

        pollDemandScores[propertyId] = demandScore;

        // Calculate adjusted target: base + (base * demandBonus / 10000)
        // High demand (>70%) gets up to 25% higher target (premium property)
        uint256 baseTarget = baseFundingTargets[propertyId];
        uint256 demandBonus = 0;

        if (demandScore >= 7000) {
            // Scale bonus: 70% demand = 0%, 100% demand = 25%
            demandBonus = ((demandScore - 7000) * MAX_DEMAND_BONUS) / 3000;
        }

        uint256 adjustedTarget = baseTarget + (baseTarget * demandBonus) / 10000;
        escrow.fundingTarget = adjustedTarget;

        emit PollDemandUpdated(propertyId, demandScore, adjustedTarget);
    }

    /**
     * @notice Get demand-adjusted funding info
     * @param propertyId Property ID
     */
    function getDemandAdjustedTarget(uint256 propertyId) external view returns (
        uint256 baseTarget,
        uint256 adjustedTarget,
        uint256 demandScore
    ) {
        return (
            baseFundingTargets[propertyId],
            propertyEscrows[propertyId].fundingTarget,
            pollDemandScores[propertyId]
        );
    }

    /**
     * @notice Purchase tokens for a property
     * @param propertyId Property ID
     * @param amount Number of tokens to purchase
     */
    function purchase(uint256 propertyId, uint256 amount) external payable nonReentrant whenNotPaused {
        PropertyEscrow storage escrow = propertyEscrows[propertyId];
        require(isPropertyActive[propertyId], "Property not active");
        require(!escrow.isComplete, "Funding complete");
        require(block.timestamp < escrow.deadline, "Funding deadline passed");

        uint256 price = propertyToken.getCurrentPrice(propertyId);
        uint256 totalCost = price * amount;
        require(msg.value >= totalCost, "Insufficient payment");

        // Record purchase
        propertyPurchases[propertyId].push(Purchase({
            buyer: msg.sender,
            propertyId: propertyId,
            amount: amount,
            price: price,
            totalPaid: totalCost,
            timestamp: block.timestamp,
            refunded: false
        }));

        // Update escrow state
        escrow.totalRaised += totalCost;
        buyerContributions[propertyId][msg.sender] += totalCost;

        // Mint tokens to buyer
        propertyToken.mintTokens(propertyId, msg.sender, amount);

        // Refund excess payment
        if (msg.value > totalCost) {
            (bool success, ) = payable(msg.sender).call{value: msg.value - totalCost}("");
            require(success, "Refund failed");
        }

        emit PurchaseReceived(propertyId, msg.sender, amount, totalCost, block.timestamp);

        // Emit compliance event for regulatory reporting
        emit CompliancePurchaseRecorded(
            propertyId,
            msg.sender,
            amount,
            totalCost,
            keccak256(abi.encodePacked(block.timestamp, msg.sender, propertyId, amount))
        );

        // Emit investor limit check for AML monitoring
        emit InvestorLimitChecked(
            propertyId,
            msg.sender,
            buyerContributions[propertyId][msg.sender] - totalCost, // previous contribution
            buyerContributions[propertyId][msg.sender], // new total contribution
            true // withinLimit - would add threshold checking in production
        );

        // Check if funding target reached
        if (escrow.totalRaised >= escrow.fundingTarget) {
            _completeFunding(propertyId);
        }
    }

    /**
     * @notice Calculate refund with 3% APR interest
     * @param principal Original investment amount
     * @param investmentTimestamp When the investment was made
     */
    function calculateRefund(uint256 principal, uint256 investmentTimestamp) public view returns (uint256) {
        uint256 duration = block.timestamp - investmentTimestamp;
        uint256 interest = (principal * REFUND_APR * duration) / (BASIS_POINTS * SECONDS_PER_YEAR);
        return principal + interest;
    }

    /**
     * @notice Process refunds for a failed property funding
     * @param propertyId Property ID
     */
    function processRefunds(uint256 propertyId) external nonReentrant {
        PropertyEscrow storage escrow = propertyEscrows[propertyId];
        require(isPropertyActive[propertyId], "Property not active");
        require(!escrow.isComplete, "Funding was successful");
        require(block.timestamp >= escrow.deadline, "Deadline not reached");
        require(!escrow.refundsProcessed, "Refunds already processed");

        escrow.refundsProcessed = true;

        emit FundingFailed(propertyId, escrow.totalRaised, escrow.fundingTarget);

        // Process all refunds and burn tokens
        Purchase[] storage purchases = propertyPurchases[propertyId];
        for (uint256 i = 0; i < purchases.length; i++) {
            Purchase storage p = purchases[i];
            if (!p.refunded) {
                uint256 refundAmount = calculateRefund(p.totalPaid, p.timestamp);
                p.refunded = true;

                // Burn buyer's tokens
                uint256 tokenBalance = propertyToken.balanceOf(p.buyer, propertyId);
                if (tokenBalance > 0) {
                    propertyToken.burnFromOnFailure(propertyId, p.buyer, tokenBalance);
                }

                (bool success, ) = payable(p.buyer).call{value: refundAmount}("");
                require(success, "Refund transfer failed");

                emit RefundProcessed(
                    propertyId,
                    p.buyer,
                    p.totalPaid,
                    refundAmount - p.totalPaid,
                    refundAmount
                );

                // Emit compliance event for regulatory reporting
                emit RefundComplianceRecorded(
                    propertyId,
                    p.buyer,
                    p.totalPaid,
                    refundAmount - p.totalPaid,
                    block.timestamp
                );
            }
        }

        // Deactivate property
        isPropertyActive[propertyId] = false;
    }

    /**
     * @notice Internal function to complete funding
     * @param propertyId Property ID
     */
    function _completeFunding(uint256 propertyId) internal {
        PropertyEscrow storage escrow = propertyEscrows[propertyId];
        escrow.isComplete = true;

        propertyToken.markFunded(propertyId);

        emit FundingComplete(propertyId, escrow.totalRaised);
    }

    /**
     * @notice Release funds to property wallet after successful funding
     * @param propertyId Property ID
     * @param recipient Recipient address
     */
    function releaseFunds(uint256 propertyId, address recipient) external onlyRole(OPERATOR_ROLE) nonReentrant {
        PropertyEscrow storage escrow = propertyEscrows[propertyId];
        require(escrow.isComplete, "Funding not complete");
        require(escrow.totalRaised > 0, "No funds to release");

        uint256 amount = escrow.totalRaised;
        escrow.totalRaised = 0;
        isPropertyActive[propertyId] = false;

        (bool success, ) = payable(recipient).call{value: amount}("");
        require(success, "Transfer failed");

        emit FundsReleased(propertyId, recipient, amount);
    }

    /**
     * @notice Get purchase history for a property
     * @param propertyId Property ID
     */
    function getPurchases(uint256 propertyId) external view returns (Purchase[] memory) {
        return propertyPurchases[propertyId];
    }

    /**
     * @notice Get escrow status for a property
     * @param propertyId Property ID
     */
    function getEscrowStatus(uint256 propertyId) external view returns (
        uint256 totalRaised,
        uint256 fundingTarget,
        uint256 deadline,
        bool isComplete,
        uint256 percentFunded
    ) {
        PropertyEscrow storage escrow = propertyEscrows[propertyId];
        uint256 percent = escrow.fundingTarget > 0 
            ? (escrow.totalRaised * 10000) / escrow.fundingTarget 
            : 0;

        return (
            escrow.totalRaised,
            escrow.fundingTarget,
            escrow.deadline,
            escrow.isComplete,
            percent
        );
    }

    // ============ Chainlink Automation ============

    /**
     * @notice Chainlink Automation check for deadline monitoring
     */
    function checkUpkeep(bytes calldata) external view override returns (bool upkeepNeeded, bytes memory performData) {
        for (uint256 i = 0; i < activeProperties.length; i++) {
            uint256 propertyId = activeProperties[i];
            PropertyEscrow storage escrow = propertyEscrows[propertyId];

            if (isPropertyActive[propertyId] && 
                !escrow.isComplete && 
                !escrow.refundsProcessed &&
                block.timestamp >= escrow.deadline) {
                return (true, abi.encode(propertyId));
            }
        }
        return (false, "");
    }

    /**
     * @notice Chainlink Automation perform upkeep
     */
    function performUpkeep(bytes calldata performData) external override {
        uint256 propertyId = abi.decode(performData, (uint256));
        PropertyEscrow storage escrow = propertyEscrows[propertyId];

        // Re-validate conditions
        require(isPropertyActive[propertyId], "Property not active");
        require(!escrow.isComplete, "Funding complete");
        require(!escrow.refundsProcessed, "Refunds processed");
        require(block.timestamp >= escrow.deadline, "Deadline not reached");

        // Trigger refund processing
        this.processRefunds(propertyId);
    }

    /**
     * @notice Pause contract
     */
    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    /**
     * @notice Unpause contract
     */
    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }

    // ============ Regulatory Compliance Functions ============

    /**
     * @notice Report suspicious activity for compliance monitoring
     * @param propertyId Property ID
     * @param account Account involved
     * @param activityType Type of suspicious activity
     */
    function reportSuspiciousActivity(
        uint256 propertyId,
        address account,
        string calldata activityType
    ) external onlyRole(OPERATOR_ROLE) {
        emit SuspiciousActivityReported(propertyId, account, activityType, block.timestamp);
    }

    /**
     * @notice Get detailed purchase history for compliance audits
     * @param propertyId Property ID
     * @param index Purchase index
     */
    function getPurchaseForAudit(uint256 propertyId, uint256 index) external view returns (
        address buyer,
        uint256 amount,
        uint256 price,
        uint256 totalPaid,
        uint256 timestamp,
        bool refunded
    ) {
        require(index < propertyPurchases[propertyId].length, "Index out of bounds");
        Purchase storage p = propertyPurchases[propertyId][index];
        return (p.buyer, p.amount, p.price, p.totalPaid, p.timestamp, p.refunded);
    }

    /**
     * @notice Get purchase count for a property (for audit iteration)
     * @param propertyId Property ID
     */
    function getPurchaseCount(uint256 propertyId) external view returns (uint256) {
        return propertyPurchases[propertyId].length;
    }

    /**
     * @notice Get investor contribution total for AML monitoring
     * @param propertyId Property ID
     * @param investor Investor address
     */
    function getInvestorContribution(uint256 propertyId, address investor) external view returns (uint256) {
        return buyerContributions[propertyId][investor];
    }

    /**
     * @notice Required for receiving ETH for refund interest buffer
     */
    receive() external payable {}
}

contracts/Governance.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";
import "@openzeppelin/contracts/utils/cryptography/MessageHashUtils.sol";

interface IPropertyToken {
    function getVotingPower(uint256 propertyId, address voter) external view returns (uint256);
    function balanceOf(address account, uint256 id) external view returns (uint256);
    function totalSupply(uint256 id) external view returns (uint256);
    function getTotalWeightedVotingPower(uint256 propertyId) external view returns (uint256);
}

/**
 * @title RevitaHub Governance
 * @notice DAO voting with phase-weighted voting power
 * @dev County holders get 1.5x, State 1.25x, National 1.0x, International 0.75x
 */
contract Governance is AccessControl, ReentrancyGuard {
    using ECDSA for bytes32;
    using MessageHashUtils for bytes32;

    bytes32 public constant PROPOSER_ROLE = keccak256("PROPOSER_ROLE");
    bytes32 public constant EXECUTOR_ROLE = keccak256("EXECUTOR_ROLE");
    bytes32 public constant RELAYER_ROLE = keccak256("RELAYER_ROLE");

    IPropertyToken public propertyToken;

    // Domain separator for EIP-712 signatures
    bytes32 public immutable DOMAIN_SEPARATOR;
    bytes32 public constant VOTE_TYPEHASH = keccak256("Vote(uint256 proposalId,uint8 support,address voter,uint256 nonce,uint256 deadline)");

    // Nonces for replay protection
    mapping(address => uint256) public nonces;

    // Proposal types
    enum ProposalType { 
        PropertyDevelopment,  // How to develop a property
        TreasuryAllocation,   // How to spend treasury funds
        ParameterChange,      // Change platform parameters
        Emergency             // Emergency actions
    }

    // Proposal status
    enum ProposalStatus {
        Pending,
        Active,
        Succeeded,
        Defeated,
        Executed,
        Cancelled
    }

    // Proposal structure
    struct Proposal {
        uint256 id;
        uint256 propertyId;
        address proposer;
        ProposalType proposalType;
        string title;
        string description;
        string ipfsHash;
        uint256 votesFor;
        uint256 votesAgainst;
        uint256 votesAbstain;
        uint256 startTime;
        uint256 endTime;
        uint256 quorumRequired;
        ProposalStatus status;
        bytes executionData;
    }

    // Vote record
    struct Vote {
        bool hasVoted;
        uint8 support; // 0 = against, 1 = for, 2 = abstain
        uint256 weight;
    }

    // Quorum requirements (basis points of total voting power)
    uint256 public constant QUORUM_PROPERTY = 2000;   // 20% for property decisions
    uint256 public constant QUORUM_TREASURY = 3000;   // 30% for treasury
    uint256 public constant QUORUM_PARAMETER = 2500;  // 25% for parameters
    uint256 public constant QUORUM_EMERGENCY = 5000;  // 50% for emergency

    // Voting period
    uint256 public votingPeriod = 7 days;

    // Vote-to-earn bonus APR (in basis points, e.g., 50 = 0.5%)
    uint256 public voteToEarnBonus = 50;

    // Storage
    mapping(uint256 => Proposal) public proposals;
    uint256 public proposalCount;

    mapping(uint256 => mapping(address => Vote)) public votes;
    mapping(uint256 => uint256) public totalVotingPower; // Total voting power at proposal creation

    // Vote-to-earn tracking
    mapping(address => uint256) public voterParticipationCount;
    mapping(address => uint256) public lastVoteTimestamp;

    // ============ Community Polls (Non-Binding Gauges) ============

    // Poll status
    enum PollStatus {
        Active,
        Ended,
        ConvertedToProposal
    }

    // Poll structure for community demand gauges
    struct Poll {
        uint256 id;
        uint256 propertyId;         // 0 for platform-wide polls
        address creator;
        string question;
        string description;
        string ipfsHash;
        uint256 votesFor;
        uint256 votesAgainst;
        uint256 startTime;
        uint256 endTime;
        PollStatus status;
        uint256 linkedProposalId;   // If converted to proposal
    }

    // Poll vote record
    struct PollVote {
        bool hasVoted;
        bool support;
    }

    // Poll storage
    mapping(uint256 => Poll) public polls;
    uint256 public pollCount;
    mapping(uint256 => mapping(address => PollVote)) public pollVotes;
    mapping(uint256 => uint256) public pollParticipants; // Total unique voters per poll

    // Poll-to-proposal threshold (30% support in basis points)
    uint256 public constant POLL_PROPOSAL_THRESHOLD = 3000;

    // Poll quorum bonus (5% reduction when poll-backed)
    uint256 public constant POLL_QUORUM_BONUS = 500;

    // Events
    event ProposalCreated(
        uint256 indexed proposalId,
        uint256 indexed propertyId,
        address proposer,
        ProposalType proposalType,
        string title
    );
    event VoteCast(
        uint256 indexed proposalId,
        address indexed voter,
        uint8 support,
        uint256 weight
    );
    event ProposalExecuted(uint256 indexed proposalId);
    event ProposalCancelled(uint256 indexed proposalId);
    event VotingPeriodUpdated(uint256 newPeriod);
    event VoteToEarnBonusUpdated(uint256 newBonus);

    // Poll events
    event PollCreated(
        uint256 indexed pollId,
        uint256 indexed propertyId,
        address creator,
        string question
    );
    event PollVoteCast(
        uint256 indexed pollId,
        address indexed voter,
        bool support
    );
    event PollEnded(uint256 indexed pollId, uint256 votesFor, uint256 votesAgainst);
    event PollConvertedToProposal(uint256 indexed pollId, uint256 indexed proposalId);

    event OffChainVoteCast(
        uint256 indexed proposalId,
        address indexed voter,
        uint8 support,
        uint256 weight,
        address relayer
    );

    constructor(address _propertyToken) {
        propertyToken = IPropertyToken(_propertyToken);
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(PROPOSER_ROLE, msg.sender);
        _grantRole(EXECUTOR_ROLE, msg.sender);
        _grantRole(RELAYER_ROLE, msg.sender);

        // Set up EIP-712 domain separator
        DOMAIN_SEPARATOR = keccak256(
            abi.encode(
                keccak256("EIP712Domain(string name,string version,uint256 chainId,address verifyingContract)"),
                keccak256(bytes("RevitaHub Governance")),
                keccak256(bytes("1")),
                block.chainid,
                address(this)
            )
        );
    }

    /**
     * @notice Create a new proposal
     * @param propertyId Property ID (0 for platform-wide proposals)
     * @param proposalType Type of proposal
     * @param title Proposal title
     * @param description Proposal description
     * @param ipfsHash IPFS hash for detailed documentation
     * @param executionData Encoded execution data
     */
    function createProposal(
        uint256 propertyId,
        ProposalType proposalType,
        string memory title,
        string memory description,
        string memory ipfsHash,
        bytes memory executionData
    ) external onlyRole(PROPOSER_ROLE) returns (uint256) {
        // Require token holdings to create proposal
        require(
            propertyToken.getVotingPower(propertyId, msg.sender) > 0,
            "Must hold tokens to propose"
        );

        uint256 proposalId = proposalCount++;
        uint256 quorum = _getQuorum(proposalType);

        // Snapshot total WEIGHTED voting power at proposal creation
        // Uses the same weighting as individual votes for consistency
        uint256 snapshotVotingPower = propertyToken.getTotalWeightedVotingPower(propertyId);
        require(snapshotVotingPower > 0, "No voting power exists for this property");
        totalVotingPower[proposalId] = snapshotVotingPower;

        proposals[proposalId] = Proposal({
            id: proposalId,
            propertyId: propertyId,
            proposer: msg.sender,
            proposalType: proposalType,
            title: title,
            description: description,
            ipfsHash: ipfsHash,
            votesFor: 0,
            votesAgainst: 0,
            votesAbstain: 0,
            startTime: block.timestamp,
            endTime: block.timestamp + votingPeriod,
            quorumRequired: quorum,
            status: ProposalStatus.Active,
            executionData: executionData
        });

        emit ProposalCreated(proposalId, propertyId, msg.sender, proposalType, title);
        return proposalId;
    }

    /**
     * @notice Cast a vote on a proposal
     * @param proposalId Proposal ID
     * @param support 0 = against, 1 = for, 2 = abstain
     */
    function castVote(uint256 proposalId, uint8 support) external nonReentrant {
        Proposal storage proposal = proposals[proposalId];
        require(proposal.status == ProposalStatus.Active, "Proposal not active");
        require(block.timestamp >= proposal.startTime, "Voting not started");
        require(block.timestamp < proposal.endTime, "Voting ended");
        require(support <= 2, "Invalid vote type");

        Vote storage voterRecord = votes[proposalId][msg.sender];
        require(!voterRecord.hasVoted, "Already voted");

        // Get voting power (phase-weighted)
        uint256 weight = propertyToken.getVotingPower(proposal.propertyId, msg.sender);
        require(weight > 0, "No voting power");

        // Record vote
        voterRecord.hasVoted = true;
        voterRecord.support = support;
        voterRecord.weight = weight;

        // Tally votes
        if (support == 0) {
            proposal.votesAgainst += weight;
        } else if (support == 1) {
            proposal.votesFor += weight;
        } else {
            proposal.votesAbstain += weight;
        }

        // Update vote-to-earn tracking
        voterParticipationCount[msg.sender]++;
        lastVoteTimestamp[msg.sender] = block.timestamp;

        emit VoteCast(proposalId, msg.sender, support, weight);
    }

    /**
     * @notice Cast a vote using off-chain signature (gasless voting)
     * @dev Enables lower-income investors to vote without paying gas
     * @param proposalId Proposal ID
     * @param support 0 = against, 1 = for, 2 = abstain
     * @param voter The address of the voter who signed
     * @param deadline Timestamp after which signature expires
     * @param v ECDSA signature component
     * @param r ECDSA signature component
     * @param s ECDSA signature component
     */
    function castVoteBySignature(
        uint256 proposalId,
        uint8 support,
        address voter,
        uint256 deadline,
        uint8 v,
        bytes32 r,
        bytes32 s
    ) external onlyRole(RELAYER_ROLE) nonReentrant {
        require(block.timestamp <= deadline, "Signature expired");

        Proposal storage proposal = proposals[proposalId];
        require(proposal.status == ProposalStatus.Active, "Proposal not active");
        require(block.timestamp >= proposal.startTime, "Voting not started");
        require(block.timestamp < proposal.endTime, "Voting ended");
        require(support <= 2, "Invalid vote type");

        Vote storage voterRecord = votes[proposalId][voter];
        require(!voterRecord.hasVoted, "Already voted");

        // Verify signature using EIP-712
        uint256 currentNonce = nonces[voter]++;
        bytes32 structHash = keccak256(
            abi.encode(VOTE_TYPEHASH, proposalId, support, voter, currentNonce, deadline)
        );
        bytes32 digest = keccak256(
            abi.encodePacked("\x19\x01", DOMAIN_SEPARATOR, structHash)
        );
        address signer = ECDSA.recover(digest, v, r, s);
        require(signer == voter, "Invalid signature");

        // Get voting power (phase-weighted)
        uint256 weight = propertyToken.getVotingPower(proposal.propertyId, voter);
        require(weight > 0, "No voting power");

        // Record vote
        voterRecord.hasVoted = true;
        voterRecord.support = support;
        voterRecord.weight = weight;

        // Tally votes
        if (support == 0) {
            proposal.votesAgainst += weight;
        } else if (support == 1) {
            proposal.votesFor += weight;
        } else {
            proposal.votesAbstain += weight;
        }

        // Update vote-to-earn tracking
        voterParticipationCount[voter]++;
        lastVoteTimestamp[voter] = block.timestamp;

        emit OffChainVoteCast(proposalId, voter, support, weight, msg.sender);
    }

    /**
     * @notice Get current nonce for a voter (for signature creation)
     * @param voter Voter address
     */
    function getNonce(address voter) external view returns (uint256) {
        return nonces[voter];
    }

    /**
     * @notice Finalize a proposal after voting ends
     * @param proposalId Proposal ID
     */
    function finalizeProposal(uint256 proposalId) external {
        Proposal storage proposal = proposals[proposalId];
        require(proposal.status == ProposalStatus.Active, "Proposal not active");
        require(block.timestamp >= proposal.endTime, "Voting not ended");

        uint256 totalVotes = proposal.votesFor + proposal.votesAgainst + proposal.votesAbstain;
        uint256 snapshotSupply = totalVotingPower[proposalId];

        // Calculate participation as basis points of total voting power
        // quorumRequired is in basis points (e.g., 2000 = 20%)
        // Check: (totalVotes * 10000) / snapshotSupply >= quorumRequired
        uint256 participationBps = snapshotSupply > 0 
            ? (totalVotes * 10000) / snapshotSupply 
            : 0;

        bool quorumReached = participationBps >= proposal.quorumRequired;
        bool majority = proposal.votesFor > proposal.votesAgainst;

        if (quorumReached && majority) {
            proposal.status = ProposalStatus.Succeeded;
        } else {
            proposal.status = ProposalStatus.Defeated;
        }
    }

    /**
     * @notice Execute a successful proposal
     * @param proposalId Proposal ID
     */
    function executeProposal(uint256 proposalId) external onlyRole(EXECUTOR_ROLE) nonReentrant {
        Proposal storage proposal = proposals[proposalId];
        require(proposal.status == ProposalStatus.Succeeded, "Proposal not succeeded");

        proposal.status = ProposalStatus.Executed;

        // Execute the proposal (implementation depends on proposal type)
        // In production, this would call the appropriate contract method

        emit ProposalExecuted(proposalId);
    }

    /**
     * @notice Cancel a proposal
     * @param proposalId Proposal ID
     */
    function cancelProposal(uint256 proposalId) external {
        Proposal storage proposal = proposals[proposalId];
        require(
            msg.sender == proposal.proposer || hasRole(DEFAULT_ADMIN_ROLE, msg.sender),
            "Not authorized"
        );
        require(
            proposal.status == ProposalStatus.Active || proposal.status == ProposalStatus.Pending,
            "Cannot cancel"
        );

        proposal.status = ProposalStatus.Cancelled;
        emit ProposalCancelled(proposalId);
    }

    /**
     * @notice Get vote-to-earn bonus eligibility
     * @param voter Voter address
     */
    function getVoteToEarnBonus(address voter) external view returns (uint256) {
        // Bonus applies if voted within last 30 days
        if (block.timestamp - lastVoteTimestamp[voter] <= 30 days) {
            return voteToEarnBonus;
        }
        return 0;
    }

    /**
     * @notice Get proposal details
     * @param proposalId Proposal ID
     */
    function getProposal(uint256 proposalId) external view returns (Proposal memory) {
        return proposals[proposalId];
    }

    /**
     * @notice Get vote details for a voter
     * @param proposalId Proposal ID
     * @param voter Voter address
     */
    function getVote(uint256 proposalId, address voter) external view returns (Vote memory) {
        return votes[proposalId][voter];
    }

    /**
     * @notice Get all active proposals for a property
     * @param propertyId Property ID to filter by
     * @return active Array of active proposals for the property
     */
    function getActiveProposals(uint256 propertyId) external view returns (Proposal[] memory) {
        uint256 count = 0;
        for (uint256 i = 0; i < proposalCount; i++) {
            if (proposals[i].propertyId == propertyId && proposals[i].status == ProposalStatus.Active) {
                count++;
            }
        }
        Proposal[] memory active = new Proposal[](count);
        uint256 idx = 0;
        for (uint256 i = 0; i < proposalCount; i++) {
            if (proposals[i].propertyId == propertyId && proposals[i].status == ProposalStatus.Active) {
                active[idx++] = proposals[i];
            }
        }
        return active;
    }

    /**
     * @notice Get quorum requirement for proposal type
     */
    function _getQuorum(ProposalType proposalType) internal pure returns (uint256) {
        if (proposalType == ProposalType.PropertyDevelopment) return QUORUM_PROPERTY;
        if (proposalType == ProposalType.TreasuryAllocation) return QUORUM_TREASURY;
        if (proposalType == ProposalType.ParameterChange) return QUORUM_PARAMETER;
        return QUORUM_EMERGENCY;
    }

    /**
     * @notice Update voting period
     * @param newPeriod New voting period in seconds
     */
    function setVotingPeriod(uint256 newPeriod) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(newPeriod >= 1 days && newPeriod <= 30 days, "Invalid period");
        votingPeriod = newPeriod;
        emit VotingPeriodUpdated(newPeriod);
    }

    /**
     * @notice Update vote-to-earn bonus
     * @param newBonus New bonus in basis points
     */
    function setVoteToEarnBonus(uint256 newBonus) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(newBonus <= 500, "Bonus too high"); // Max 5%
        voteToEarnBonus = newBonus;
        emit VoteToEarnBonusUpdated(newBonus);
    }

    // ============ Community Poll Functions ============

    /**
     * @notice Create a non-binding community poll to gauge demand
     * @dev Polls are lightweight and don't require token holdings
     * @param propertyId Property ID (0 for platform-wide)
     * @param question Poll question
     * @param description Detailed description
     * @param ipfsHash IPFS hash for additional docs
     * @param duration Poll duration in seconds
     */
    function createPoll(
        uint256 propertyId,
        string memory question,
        string memory description,
        string memory ipfsHash,
        uint256 duration
    ) external returns (uint256) {
        require(duration >= 1 days && duration <= 30 days, "Invalid duration");

        uint256 pollId = pollCount++;

        polls[pollId] = Poll({
            id: pollId,
            propertyId: propertyId,
            creator: msg.sender,
            question: question,
            description: description,
            ipfsHash: ipfsHash,
            votesFor: 0,
            votesAgainst: 0,
            startTime: block.timestamp,
            endTime: block.timestamp + duration,
            status: PollStatus.Active,
            linkedProposalId: 0
        });

        emit PollCreated(pollId, propertyId, msg.sender, question);
        return pollId;
    }

    /**
     * @notice Vote on a community poll (no gas subsidy needed - lightweight)
     * @param pollId Poll ID
     * @param support True = support, False = oppose
     */
    function votePoll(uint256 pollId, bool support) external {
        Poll storage poll = polls[pollId];
        require(poll.status == PollStatus.Active, "Poll not active");
        require(block.timestamp < poll.endTime, "Poll ended");

        PollVote storage voterRecord = pollVotes[pollId][msg.sender];
        require(!voterRecord.hasVoted, "Already voted");

        voterRecord.hasVoted = true;
        voterRecord.support = support;
        pollParticipants[pollId]++;

        if (support) {
            poll.votesFor++;
        } else {
            poll.votesAgainst++;
        }

        emit PollVoteCast(pollId, msg.sender, support);
    }

    /**
     * @notice End a poll and calculate results
     * @param pollId Poll ID
     */
    function endPoll(uint256 pollId) external {
        Poll storage poll = polls[pollId];
        require(poll.status == PollStatus.Active, "Poll not active");
        require(block.timestamp >= poll.endTime, "Poll not ended yet");

        poll.status = PollStatus.Ended;
        emit PollEnded(pollId, poll.votesFor, poll.votesAgainst);
    }

    /**
     * @notice Create a proposal from a successful poll (poll-to-proposal pipeline)
     * @dev Requires >30% support in the poll for reduced quorum
     * @param pollId Poll ID to convert
     * @param proposalType Type of proposal to create
     * @param executionData Encoded execution data
     */
    function createProposalFromPoll(
        uint256 pollId,
        ProposalType proposalType,
        bytes memory executionData
    ) external onlyRole(PROPOSER_ROLE) returns (uint256) {
        Poll storage poll = polls[pollId];
        require(poll.status == PollStatus.Ended, "Poll must be ended first");
        require(poll.linkedProposalId == 0, "Already converted");

        // Calculate poll support percentage
        uint256 totalVotes = poll.votesFor + poll.votesAgainst;
        require(totalVotes > 0, "No votes cast");
        uint256 supportPercent = (poll.votesFor * 10000) / totalVotes;
        require(supportPercent >= POLL_PROPOSAL_THRESHOLD, "Insufficient poll support");

        // Require token holdings
        require(
            propertyToken.getVotingPower(poll.propertyId, msg.sender) > 0,
            "Must hold tokens to propose"
        );

        uint256 proposalId = proposalCount++;

        // Apply quorum bonus for poll-backed proposals
        uint256 baseQuorum = _getQuorum(proposalType);
        uint256 adjustedQuorum = baseQuorum > POLL_QUORUM_BONUS 
            ? baseQuorum - POLL_QUORUM_BONUS 
            : baseQuorum;

        // Snapshot voting power
        uint256 snapshotVotingPower = propertyToken.getTotalWeightedVotingPower(poll.propertyId);
        require(snapshotVotingPower > 0, "No voting power exists");
        totalVotingPower[proposalId] = snapshotVotingPower;

        proposals[proposalId] = Proposal({
            id: proposalId,
            propertyId: poll.propertyId,
            proposer: msg.sender,
            proposalType: proposalType,
            title: poll.question,
            description: poll.description,
            ipfsHash: poll.ipfsHash,
            votesFor: 0,
            votesAgainst: 0,
            votesAbstain: 0,
            startTime: block.timestamp,
            endTime: block.timestamp + votingPeriod,
            quorumRequired: adjustedQuorum,
            status: ProposalStatus.Active,
            executionData: executionData
        });

        // Link poll to proposal
        poll.status = PollStatus.ConvertedToProposal;
        poll.linkedProposalId = proposalId;

        emit ProposalCreated(proposalId, poll.propertyId, msg.sender, proposalType, poll.question);
        emit PollConvertedToProposal(pollId, proposalId);

        return proposalId;
    }

    /**
     * @notice Get poll details
     * @param pollId Poll ID
     */
    function getPoll(uint256 pollId) external view returns (Poll memory) {
        return polls[pollId];
    }

    /**
     * @notice Get poll support percentage
     * @param pollId Poll ID
     * @return supportPercent Support in basis points (e.g., 6000 = 60%)
     */
    function getPollSupport(uint256 pollId) external view returns (uint256) {
        Poll storage poll = polls[pollId];
        uint256 totalVotes = poll.votesFor + poll.votesAgainst;
        if (totalVotes == 0) return 0;
        return (poll.votesFor * 10000) / totalVotes;
    }

    /**
     * @notice Get active polls for a property
     * @param propertyId Property ID (0 for platform-wide)
     */
    function getActivePolls(uint256 propertyId) external view returns (Poll[] memory) {
        uint256 count = 0;
        for (uint256 i = 0; i < pollCount; i++) {
            if (polls[i].propertyId == propertyId && polls[i].status == PollStatus.Active) {
                count++;
            }
        }
        Poll[] memory active = new Poll[](count);
        uint256 idx = 0;
        for (uint256 i = 0; i < pollCount; i++) {
            if (polls[i].propertyId == propertyId && polls[i].status == PollStatus.Active) {
                active[idx++] = polls[i];
            }
        }
        return active;
    }
}

contracts/PhaseManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@chainlink/contracts/src/v0.8/automation/AutomationCompatible.sol";

interface IPropertyToken {
    enum Phase { County, State, National, International }

    function advancePhase(uint256 propertyId) external;
    function mintTokens(uint256 propertyId, address buyer, uint256 amount) external;
    function getProperty(uint256 propertyId) external view returns (
        uint256 id,
        string memory name,
        string memory uri,
        uint256 totalSupply,
        uint256 mintedSupply,
        uint256 fundingTarget,
        uint256 fundingDeadline,
        uint8 currentPhase,
        bool isActive,
        bool isFunded
    );
    function phaseAllocations(uint256 propertyId, uint8 phase) external view returns (uint256);
    function phaseMinted(uint256 propertyId, uint8 phase) external view returns (uint256);
    function whitelist(address account) external view returns (bool);
}

interface IGovernance {
    function proposalCount() external view returns (uint256);
    function getProposal(uint256 proposalId) external view returns (
        uint256 id,
        uint256 propertyId,
        address proposer,
        uint8 proposalType,
        string memory title,
        string memory description,
        string memory ipfsHash,
        uint256 votesFor,
        uint256 votesAgainst,
        uint256 votesAbstain,
        uint256 startTime,
        uint256 endTime,
        uint256 quorumRequired,
        uint8 status,
        bytes memory executionData
    );
}

/**
 * @title RevitaHub Phase Manager
 * @notice Dynamic phase advancement based on engagement analytics
 * @dev Advances phases when 75% engagement threshold OR full subscription is reached
 */
contract PhaseManager is AccessControl, AutomationCompatibleInterface {
    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");

    IPropertyToken public propertyToken;
    IGovernance public governance;

    // Engagement threshold for early phase advancement (basis points)
    uint256 public constant ENGAGEMENT_THRESHOLD = 7500; // 75%

    // Minimum engagement period before early advancement (prevents gaming)
    uint256 public constant MIN_ENGAGEMENT_PERIOD = 7 days;

    // Property engagement tracking
    struct PropertyEngagement {
        uint256 propertyId;
        uint256 phaseStartTime;
        uint256 totalEligibleVoters;
        uint256 activeVoters;
        uint256 totalProposals;
        uint256 votedProposals;
        bool isTracking;
    }

    // Engagement metrics per property
    mapping(uint256 => PropertyEngagement) public propertyEngagement;

    // Active properties for automation
    uint256[] public trackedProperties;
    mapping(uint256 => bool) public isTracked;

    // Behavioral nudge triggers
    mapping(uint256 => uint256) public lastNudgeTime;
    uint256 public nudgeCooldown = 24 hours;

    // Engagement bonus tracking (vote-to-earn)
    mapping(uint256 => mapping(address => bool)) public hasClaimed;
    uint256 public constant BONUS_TOKENS = 1; // Tokens awarded for engagement bonus

    // Poll participation bonuses
    mapping(uint256 => mapping(address => bool)) public pollParticipated; // Track poll voters
    mapping(uint256 => uint256) public propertyPollCount; // Number of polls per property
    uint256 public constant POLL_BONUS_MULTIPLIER = 50; // 0.5 extra engagement credit per poll vote (in basis points)

    // Events
    event EngagementUpdated(
        uint256 indexed propertyId,
        uint256 activeVoters,
        uint256 totalEligible,
        uint256 engagementPercent
    );
    event PhaseAdvancedByEngagement(
        uint256 indexed propertyId,
        uint8 fromPhase,
        uint8 toPhase,
        uint256 engagementPercent
    );
    event PhaseAdvancedBySubscription(
        uint256 indexed propertyId,
        uint8 fromPhase,
        uint8 toPhase
    );
    event NudgeTriggered(
        uint256 indexed propertyId,
        string nudgeType,
        uint256 engagementPercent
    );
    event PropertyTrackingStarted(uint256 indexed propertyId);
    event PropertyTrackingStopped(uint256 indexed propertyId);
    event BonusClaimed(uint256 indexed propertyId, address indexed claimer, uint256 bonus);
    event PollParticipationRecorded(uint256 indexed propertyId, address indexed participant);
    event PollBonusApplied(uint256 indexed propertyId, uint256 pollParticipants, uint256 bonusEngagement);

    constructor(address _propertyToken, address _governance) {
        propertyToken = IPropertyToken(_propertyToken);
        governance = IGovernance(_governance);
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(OPERATOR_ROLE, msg.sender);
    }

    /**
     * @notice Start tracking engagement for a property
     * @param propertyId Property ID
     * @param totalEligibleVoters Total number of eligible voters
     */
    function startTracking(uint256 propertyId, uint256 totalEligibleVoters) external onlyRole(OPERATOR_ROLE) {
        require(!isTracked[propertyId], "Already tracking");

        propertyEngagement[propertyId] = PropertyEngagement({
            propertyId: propertyId,
            phaseStartTime: block.timestamp,
            totalEligibleVoters: totalEligibleVoters,
            activeVoters: 0,
            totalProposals: 0,
            votedProposals: 0,
            isTracking: true
        });

        trackedProperties.push(propertyId);
        isTracked[propertyId] = true;

        emit PropertyTrackingStarted(propertyId);
    }

    /**
     * @notice Update engagement metrics for a property
     * @param propertyId Property ID
     * @param activeVoters Number of unique voters
     * @param totalProposals Total proposals for property
     * @param votedProposals Proposals with votes
     */
    function updateEngagement(
        uint256 propertyId,
        uint256 activeVoters,
        uint256 totalProposals,
        uint256 votedProposals
    ) external onlyRole(OPERATOR_ROLE) {
        PropertyEngagement storage engagement = propertyEngagement[propertyId];
        require(engagement.isTracking, "Not tracking");

        engagement.activeVoters = activeVoters;
        engagement.totalProposals = totalProposals;
        engagement.votedProposals = votedProposals;

        uint256 engagementPercent = calculateEngagement(propertyId);
        emit EngagementUpdated(propertyId, activeVoters, engagement.totalEligibleVoters, engagementPercent);

        // Check for nudge triggers
        _checkNudges(propertyId, engagementPercent);

        // Check for early phase advancement
        _checkPhaseAdvancement(propertyId, engagementPercent);
    }

    /**
     * @notice Calculate engagement percentage
     * @param propertyId Property ID
     */
    function calculateEngagement(uint256 propertyId) public view returns (uint256) {
        PropertyEngagement storage engagement = propertyEngagement[propertyId];
        if (engagement.totalEligibleVoters == 0) return 0;

        // Engagement = (active voters / eligible voters) * 100
        // Returns in basis points (e.g., 7500 = 75%)
        return (engagement.activeVoters * 10000) / engagement.totalEligibleVoters;
    }

    /**
     * @notice Check if phase should advance based on engagement
     * @param propertyId Property ID
     * @param engagementPercent Current engagement in basis points
     */
    function _checkPhaseAdvancement(uint256 propertyId, uint256 engagementPercent) internal {
        PropertyEngagement storage engagement = propertyEngagement[propertyId];

        // Check minimum engagement period
        if (block.timestamp < engagement.phaseStartTime + MIN_ENGAGEMENT_PERIOD) {
            return;
        }

        // Check engagement threshold
        if (engagementPercent >= ENGAGEMENT_THRESHOLD) {
            _advancePhaseByEngagement(propertyId, engagementPercent);
        }
    }

    /**
     * @notice Advance phase due to high engagement
     * @param propertyId Property ID
     * @param engagementPercent Engagement that triggered advancement
     */
    function _advancePhaseByEngagement(uint256 propertyId, uint256 engagementPercent) internal {
        (,,,,,,,uint8 currentPhase,,) = propertyToken.getProperty(propertyId);

        if (currentPhase < 3) { // Not at International yet
            propertyToken.advancePhase(propertyId);

            // Reset phase tracking
            propertyEngagement[propertyId].phaseStartTime = block.timestamp;
            propertyEngagement[propertyId].activeVoters = 0;

            emit PhaseAdvancedByEngagement(propertyId, currentPhase, currentPhase + 1, engagementPercent);
        }
    }

    /**
     * @notice Check and trigger behavioral nudges
     * @param propertyId Property ID
     * @param engagementPercent Current engagement
     */
    function _checkNudges(uint256 propertyId, uint256 engagementPercent) internal {
        if (block.timestamp < lastNudgeTime[propertyId] + nudgeCooldown) {
            return;
        }

        string memory nudgeType;

        if (engagementPercent < 2500) {
            // Low engagement - urgent nudge
            nudgeType = "urgent_participation";
        } else if (engagementPercent >= 6000 && engagementPercent < 7500) {
            // Near threshold - milestone nudge
            nudgeType = "milestone_near";
        } else if (engagementPercent >= 7000 && engagementPercent < 7500) {
            // Very close - final push nudge
            nudgeType = "phase_closing";
        } else {
            return; // No nudge needed
        }

        lastNudgeTime[propertyId] = block.timestamp;
        emit NudgeTriggered(propertyId, nudgeType, engagementPercent);
    }

    /**
     * @notice Manually trigger phase check (for subscription-based advancement)
     * @param propertyId Property ID
     */
    function checkSubscriptionAdvancement(uint256 propertyId) external {
        (,,,,,,,uint8 currentPhase,,) = propertyToken.getProperty(propertyId);

        uint256 phaseAllocation = propertyToken.phaseAllocations(propertyId, currentPhase);
        uint256 phaseMinted = propertyToken.phaseMinted(propertyId, currentPhase);

        if (phaseMinted >= phaseAllocation && currentPhase < 3) {
            propertyToken.advancePhase(propertyId);

            // Reset tracking for new phase
            propertyEngagement[propertyId].phaseStartTime = block.timestamp;
            propertyEngagement[propertyId].activeVoters = 0;

            emit PhaseAdvancedBySubscription(propertyId, currentPhase, currentPhase + 1);
        }
    }

    // ============ Chainlink Automation ============

    /**
     * @notice Chainlink Automation check
     */
    function checkUpkeep(bytes calldata) external view override returns (bool upkeepNeeded, bytes memory performData) {
        for (uint256 i = 0; i < trackedProperties.length; i++) {
            uint256 propertyId = trackedProperties[i];
            PropertyEngagement storage engagement = propertyEngagement[propertyId];

            if (!engagement.isTracking) continue;

            // Check if minimum period passed
            if (block.timestamp < engagement.phaseStartTime + MIN_ENGAGEMENT_PERIOD) continue;

            uint256 engagementPercent = calculateEngagement(propertyId);

            if (engagementPercent >= ENGAGEMENT_THRESHOLD) {
                return (true, abi.encode(propertyId, engagementPercent));
            }
        }
        return (false, "");
    }

    /**
     * @notice Chainlink Automation perform
     */
    function performUpkeep(bytes calldata performData) external override {
        (uint256 propertyId, uint256 engagementPercent) = abi.decode(performData, (uint256, uint256));

        PropertyEngagement storage engagement = propertyEngagement[propertyId];
        require(engagement.isTracking, "Not tracking");
        require(block.timestamp >= engagement.phaseStartTime + MIN_ENGAGEMENT_PERIOD, "Too early");

        // Re-verify engagement
        uint256 currentEngagement = calculateEngagement(propertyId);
        require(currentEngagement >= ENGAGEMENT_THRESHOLD, "Threshold not met");

        _advancePhaseByEngagement(propertyId, currentEngagement);
    }

    /**
     * @notice Stop tracking a property
     * @param propertyId Property ID
     */
    function stopTracking(uint256 propertyId) external onlyRole(OPERATOR_ROLE) {
        require(isTracked[propertyId], "Not tracking");

        propertyEngagement[propertyId].isTracking = false;
        isTracked[propertyId] = false;

        emit PropertyTrackingStopped(propertyId);
    }

    /**
     * @notice Update nudge cooldown
     * @param newCooldown New cooldown in seconds
     */
    function setNudgeCooldown(uint256 newCooldown) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(newCooldown >= 1 hours && newCooldown <= 7 days, "Invalid cooldown");
        nudgeCooldown = newCooldown;
    }

    /**
     * @notice Get all tracked properties
     */
    function getTrackedProperties() external view returns (uint256[] memory) {
        return trackedProperties;
    }

    /**
     * @notice Claim engagement bonus when threshold is met (vote-to-earn)
     * @dev Mints bonus tokens to active participants when 75% engagement is reached
     * @param propertyId Property ID
     */
    function claimEngagementBonus(uint256 propertyId) external {
        require(propertyToken.whitelist(msg.sender), "Not whitelisted");
        require(!hasClaimed[propertyId][msg.sender], "Already claimed");

        PropertyEngagement storage engagement = propertyEngagement[propertyId];
        require(engagement.isTracking, "Not tracking");
        require(calculateEngagement(propertyId) >= ENGAGEMENT_THRESHOLD, "Threshold not met");
        require(block.timestamp >= engagement.phaseStartTime + MIN_ENGAGEMENT_PERIOD, "Too early");

        // Mark as claimed before minting (reentrancy protection)
        hasClaimed[propertyId][msg.sender] = true;

        // Mint bonus tokens (requires MINTER_ROLE granted to PhaseManager)
        propertyToken.mintTokens(propertyId, msg.sender, BONUS_TOKENS);

        emit BonusClaimed(propertyId, msg.sender, BONUS_TOKENS);
    }

    /**
     * @notice Get engagement details for a property
     * @param propertyId Property ID
     */
    function getEngagement(uint256 propertyId) external view returns (
        uint256 phaseStartTime,
        uint256 totalEligible,
        uint256 activeVoters,
        uint256 engagementPercent,
        bool isTracking
    ) {
        PropertyEngagement storage engagement = propertyEngagement[propertyId];
        return (
            engagement.phaseStartTime,
            engagement.totalEligibleVoters,
            engagement.activeVoters,
            calculateEngagement(propertyId),
            engagement.isTracking
        );
    }

    // ============ Poll Bonus Functions ============

    /**
     * @notice Record poll participation for engagement bonus credit
     * @dev Called by operator when user votes on a property-related poll
     * @param propertyId Property ID
     * @param participant Address of poll participant
     */
    function recordPollParticipation(
        uint256 propertyId,
        address participant
    ) external onlyRole(OPERATOR_ROLE) {
        require(isTracked[propertyId], "Property not tracked");
        require(!pollParticipated[propertyId][participant], "Already recorded");

        pollParticipated[propertyId][participant] = true;
        emit PollParticipationRecorded(propertyId, participant);
    }

    /**
     * @notice Update engagement with poll participation bonus
     * @dev Adds half-credit for poll voters to boost engagement calculation
     * @param propertyId Property ID
     * @param activeVoters Number of unique proposal voters
     * @param totalProposals Total proposals for property
     * @param votedProposals Proposals with votes
     * @param pollParticipants Number of unique poll voters
     */
    function updateEngagementWithPolls(
        uint256 propertyId,
        uint256 activeVoters,
        uint256 totalProposals,
        uint256 votedProposals,
        uint256 pollParticipants
    ) external onlyRole(OPERATOR_ROLE) {
        PropertyEngagement storage engagement = propertyEngagement[propertyId];
        require(engagement.isTracking, "Not tracking");

        // Calculate poll bonus: half credit per poll voter
        // pollParticipants / 2 added to active voters (but not exceeding totalEligible)
        uint256 pollBonus = (pollParticipants * POLL_BONUS_MULTIPLIER) / 100;
        uint256 adjustedActiveVoters = activeVoters + pollBonus;

        // Cap at total eligible voters
        if (adjustedActiveVoters > engagement.totalEligibleVoters) {
            adjustedActiveVoters = engagement.totalEligibleVoters;
        }

        engagement.activeVoters = adjustedActiveVoters;
        engagement.totalProposals = totalProposals;
        engagement.votedProposals = votedProposals;

        uint256 engagementPercent = calculateEngagement(propertyId);
        emit EngagementUpdated(propertyId, adjustedActiveVoters, engagement.totalEligibleVoters, engagementPercent);
        emit PollBonusApplied(propertyId, pollParticipants, pollBonus);

        // Check for nudge triggers
        _checkNudges(propertyId, engagementPercent);

        // Check for early phase advancement
        _checkPhaseAdvancement(propertyId, engagementPercent);
    }

    /**
     * @notice Claim poll-boosted engagement bonus
     * @dev Extra bonus tokens for poll participants when threshold met
     * @param propertyId Property ID
     */
    function claimPollBoostBonus(uint256 propertyId) external {
        require(propertyToken.whitelist(msg.sender), "Not whitelisted");
        require(pollParticipated[propertyId][msg.sender], "Did not participate in polls");
        require(!hasClaimed[propertyId][msg.sender], "Already claimed");

        PropertyEngagement storage engagement = propertyEngagement[propertyId];
        require(engagement.isTracking, "Not tracking");
        require(calculateEngagement(propertyId) >= ENGAGEMENT_THRESHOLD, "Threshold not met");
        require(block.timestamp >= engagement.phaseStartTime + MIN_ENGAGEMENT_PERIOD, "Too early");

        hasClaimed[propertyId][msg.sender] = true;

        // Poll participants get 2x bonus
        uint256 bonusAmount = BONUS_TOKENS * 2;
        propertyToken.mintTokens(propertyId, msg.sender, bonusAmount);

        emit BonusClaimed(propertyId, msg.sender, bonusAmount);
    }

    /**
     * @notice Check if user participated in polls for a property
     * @param propertyId Property ID
     * @param participant User address
     */
    function hasParticipatedInPolls(uint256 propertyId, address participant) external view returns (bool) {
        return pollParticipated[propertyId][participant];
    }
}

contracts/Treasury.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title IChainlinkFunctions
 * @notice Interface for Chainlink Functions oracle for reserve verification
 * @dev In production, use actual Chainlink Functions Router interface
 */
interface IChainlinkFunctions {
    function getReserves(uint256 propertyId) external view returns (uint256);
}

/**
 * @title RevitaHub Treasury
 * @notice DAO-controlled treasury with multi-sig, founder sustainability fee, and reserve verification
 * @dev Implements 2-of-3 multi-sig for institutional credibility
 */
contract Treasury is AccessControl, ReentrancyGuard {
    bytes32 public constant EXECUTOR_ROLE = keccak256("EXECUTOR_ROLE");
    bytes32 public constant SIGNER_ROLE = keccak256("SIGNER_ROLE");

    address public founderWallet;
    address public chainlinkOracle;
    uint256 public constant FOUNDER_CUT_BPS = 100; // 1% in basis points

    // Multi-sig configuration
    uint256 public requiredConfirmations = 2; // 2-of-3 default
    uint256 public transactionCount;

    // Vesting schedule for founder cuts (24 months)
    uint256 public constant VESTING_PERIOD = 730 days; // ~24 months
    uint256 public constant VESTING_CLIFF = 90 days; // 3 month cliff
    mapping(address => uint256) public vestedCuts; // Total vested amount per founder
    mapping(address => uint256) public vestingStart; // When vesting started
    mapping(address => uint256) public claimedCuts; // Already claimed amount

    // Relayer reimbursement for gasless voting
    uint256 public relayerReimbursementPool;
    uint256 public maxReimbursementPerTx = 0.01 ether; // Max reimbursement per transaction
    mapping(address => uint256) public relayerReimbursements; // Total reimbursed per relayer

    // Transaction structure for multi-sig
    struct Transaction {
        address target;
        uint256 value;
        bytes data;
        bool executed;
        uint256 confirmationCount;
    }

    // Transaction storage
    mapping(uint256 => Transaction) public transactions;
    mapping(uint256 => mapping(address => bool)) public confirmations;

    event FounderCutSent(address indexed founder, uint256 amount);
    event Executed(address indexed target, uint256 value, bytes data);
    event FounderWalletUpdated(address indexed oldWallet, address indexed newWallet);
    event ChainlinkOracleUpdated(address indexed oldOracle, address indexed newOracle);
    event ReservesVerified(uint256 indexed propertyId, uint256 reserves);
    event TransactionSubmitted(uint256 indexed txId, address indexed submitter, address target, uint256 value);
    event TransactionConfirmed(uint256 indexed txId, address indexed signer);
    event TransactionRevoked(uint256 indexed txId, address indexed signer);
    event TransactionExecuted(uint256 indexed txId);
    event RequiredConfirmationsUpdated(uint256 oldRequired, uint256 newRequired);
    event SignerAdded(address indexed signer);
    event SignerRemoved(address indexed signer);

    // Vesting and reimbursement events
    event VestedCutAccrued(address indexed founder, uint256 amount, uint256 totalVested);
    event VestedCutClaimed(address indexed founder, uint256 amount, uint256 remaining);
    event RelayerReimbursed(address indexed relayer, uint256 amount, uint256 poolRemaining);
    event ReimbursementPoolFunded(uint256 amount, uint256 newTotal);
    event MaxReimbursementUpdated(uint256 oldMax, uint256 newMax);

    constructor(address _founderWallet) {
        require(_founderWallet != address(0), "Invalid founder wallet");
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(SIGNER_ROLE, msg.sender);
        founderWallet = _founderWallet;
    }

    receive() external payable {}

    // ============ Multi-Sig Functions ============

    /**
     * @notice Submit a new transaction for multi-sig approval
     * @param target Target address for the transaction
     * @param value ETH value to send
     * @param data Calldata for the transaction
     */
    function submitTransaction(
        address target,
        uint256 value,
        bytes calldata data
    ) external onlyRole(SIGNER_ROLE) returns (uint256) {
        uint256 txId = transactionCount++;

        transactions[txId] = Transaction({
            target: target,
            value: value,
            data: data,
            executed: false,
            confirmationCount: 0
        });

        emit TransactionSubmitted(txId, msg.sender, target, value);

        // Auto-confirm for submitter
        confirmTransaction(txId);

        return txId;
    }

    /**
     * @notice Confirm a pending transaction
     * @param txId Transaction ID to confirm
     */
    function confirmTransaction(uint256 txId) public onlyRole(SIGNER_ROLE) {
        require(txId < transactionCount, "Transaction does not exist");
        require(!transactions[txId].executed, "Transaction already executed");
        require(!confirmations[txId][msg.sender], "Already confirmed");

        confirmations[txId][msg.sender] = true;
        transactions[txId].confirmationCount++;

        emit TransactionConfirmed(txId, msg.sender);
    }

    /**
     * @notice Revoke a previous confirmation
     * @param txId Transaction ID to revoke confirmation
     */
    function revokeConfirmation(uint256 txId) external onlyRole(SIGNER_ROLE) {
        require(txId < transactionCount, "Transaction does not exist");
        require(!transactions[txId].executed, "Transaction already executed");
        require(confirmations[txId][msg.sender], "Not confirmed");

        confirmations[txId][msg.sender] = false;
        transactions[txId].confirmationCount--;

        emit TransactionRevoked(txId, msg.sender);
    }

    /**
     * @notice Execute a confirmed transaction (requires enough confirmations)
     * @param txId Transaction ID to execute
     */
    function executeTransaction(uint256 txId) external onlyRole(SIGNER_ROLE) nonReentrant returns (bytes memory) {
        require(txId < transactionCount, "Transaction does not exist");
        Transaction storage txn = transactions[txId];
        require(!txn.executed, "Transaction already executed");
        require(txn.confirmationCount >= requiredConfirmations, "Not enough confirmations");
        require(address(this).balance >= txn.value, "Insufficient treasury balance");

        txn.executed = true;

        uint256 founderCut = (txn.value * FOUNDER_CUT_BPS) / 10000;
        uint256 amountToSend = txn.value - founderCut;

        // Send founder cut first
        if (founderCut > 0) {
            (bool founderSuccess, ) = payable(founderWallet).call{value: founderCut}("");
            require(founderSuccess, "Founder cut transfer failed");
            emit FounderCutSent(founderWallet, founderCut);
        }

        // Execute the transaction
        (bool success, bytes memory result) = txn.target.call{value: amountToSend}(txn.data);
        require(success, "Transaction execution failed");

        emit TransactionExecuted(txId);
        emit Executed(txn.target, amountToSend, txn.data);

        return result;
    }

    /**
     * @notice Get transaction details
     * @param txId Transaction ID
     */
    function getTransaction(uint256 txId) external view returns (
        address target,
        uint256 value,
        bytes memory data,
        bool executed,
        uint256 confirmationCount
    ) {
        Transaction storage txn = transactions[txId];
        return (txn.target, txn.value, txn.data, txn.executed, txn.confirmationCount);
    }

    /**
     * @notice Check if an address has confirmed a transaction
     * @param txId Transaction ID
     * @param signer Signer address
     */
    function isConfirmed(uint256 txId, address signer) external view returns (bool) {
        return confirmations[txId][signer];
    }

    // ============ Governance Direct Execute ============
    // ARCHITECTURAL NOTE: Two execution paths exist by design:
    // 1. Multi-sig (submitTransaction → confirmations → executeTransaction): For operational disbursements
    // 2. Direct execute(): For DAO-approved proposals (Governance contract holds EXECUTOR_ROLE)
    //
    // The Governance contract provides its own approval mechanism (proposal voting with quorum),
    // which satisfies institutional governance requirements. Multi-sig is for non-governance operations.
    // In production: EXECUTOR_ROLE should ONLY be granted to the Governance contract.

    /**
     * @notice Direct execute for DAO-approved proposals via Governance contract
     * @dev EXECUTOR_ROLE should ONLY be assigned to Governance contract (which has its own voting approval)
     * @dev This is NOT a bypass - Governance proposals require majority vote to reach this point
     */
    function execute(
        address target,
        uint256 value,
        bytes calldata data
    ) external onlyRole(EXECUTOR_ROLE) nonReentrant returns (bytes memory) {
        require(address(this).balance >= value, "Insufficient treasury balance");

        uint256 founderCut = (value * FOUNDER_CUT_BPS) / 10000; // 1% basis points
        uint256 amountToSend = value - founderCut;

        // Send founder cut first
        if (founderCut > 0) {
            (bool founderSuccess, ) = payable(founderWallet).call{value: founderCut}("");
            require(founderSuccess, "Founder cut transfer failed");
            emit FounderCutSent(founderWallet, founderCut);
        }

        // Execute the rest
        (bool success, bytes memory result) = target.call{value: amountToSend}(data);
        require(success, "Call failed");

        emit Executed(target, amountToSend, data);
        return result;
    }

    // ============ Admin Functions ============

    /**
     * @notice Add a new signer
     * @param signer Address to add as signer
     */
    function addSigner(address signer) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(signer != address(0), "Invalid signer address");
        _grantRole(SIGNER_ROLE, signer);
        emit SignerAdded(signer);
    }

    /**
     * @notice Remove a signer
     * @param signer Address to remove as signer
     */
    function removeSigner(address signer) external onlyRole(DEFAULT_ADMIN_ROLE) {
        _revokeRole(SIGNER_ROLE, signer);
        emit SignerRemoved(signer);
    }

    /**
     * @notice Update required confirmations
     * @param _requiredConfirmations New required confirmations count
     */
    function setRequiredConfirmations(uint256 _requiredConfirmations) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(_requiredConfirmations > 0, "Must require at least 1 confirmation");
        require(_requiredConfirmations <= 10, "Cannot require more than 10 confirmations");
        uint256 oldRequired = requiredConfirmations;
        requiredConfirmations = _requiredConfirmations;
        emit RequiredConfirmationsUpdated(oldRequired, _requiredConfirmations);
    }

    function updateFounderWallet(address _newFounderWallet) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(_newFounderWallet != address(0), "Invalid founder wallet");
        address oldWallet = founderWallet;
        founderWallet = _newFounderWallet;
        emit FounderWalletUpdated(oldWallet, _newFounderWallet);
    }

    function withdraw(uint256 amount) external onlyRole(DEFAULT_ADMIN_ROLE) nonReentrant {
        require(address(this).balance >= amount, "Insufficient balance");
        (bool success, ) = payable(msg.sender).call{value: amount}("");
        require(success, "Withdraw failed");
    }

    function getBalance() external view returns (uint256) {
        return address(this).balance;
    }

    /**
     * @notice Set the Chainlink Functions oracle address
     * @param _chainlinkOracle Address of the Chainlink Functions oracle
     */
    function setChainlinkOracle(address _chainlinkOracle) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(_chainlinkOracle != address(0), "Invalid oracle address");
        address oldOracle = chainlinkOracle;
        chainlinkOracle = _chainlinkOracle;
        emit ChainlinkOracleUpdated(oldOracle, _chainlinkOracle);
    }

    /**
     * @notice Verify reserves for a property via Chainlink Functions
     * @dev Calls Chainlink oracle to fetch LLC/rent balances for proof-of-reserves
     * @param propertyId Property ID to verify reserves for
     * @return reserves The verified reserve amount in wei
     */
    function verifyReserves(uint256 propertyId) external view returns (uint256) {
        require(chainlinkOracle != address(0), "Oracle not configured");
        return IChainlinkFunctions(chainlinkOracle).getReserves(propertyId);
    }

    /**
     * @notice Verify reserves and emit event (non-view for on-chain record)
     * @param propertyId Property ID to verify
     */
    function verifyAndRecordReserves(uint256 propertyId) external returns (uint256) {
        require(chainlinkOracle != address(0), "Oracle not configured");
        uint256 reserves = IChainlinkFunctions(chainlinkOracle).getReserves(propertyId);
        emit ReservesVerified(propertyId, reserves);
        return reserves;
    }

    // ============ Vesting Functions ============

    /**
     * @notice Accrue founder cut to vesting schedule instead of immediate payout
     * @dev Called internally when founder cuts would normally be sent
     * @param founder Founder address
     * @param amount Amount to vest
     */
    function _accrueVestedCut(address founder, uint256 amount) internal {
        if (vestingStart[founder] == 0) {
            vestingStart[founder] = block.timestamp;
        }
        vestedCuts[founder] += amount;
        emit VestedCutAccrued(founder, amount, vestedCuts[founder]);
    }

    /**
     * @notice Calculate claimable vested amount
     * @param founder Founder address
     */
    function getClaimableVested(address founder) public view returns (uint256) {
        if (vestingStart[founder] == 0) return 0;

        uint256 elapsed = block.timestamp - vestingStart[founder];
        if (elapsed < VESTING_CLIFF) return 0;

        uint256 totalVested = vestedCuts[founder];
        uint256 vestedAmount;

        if (elapsed >= VESTING_PERIOD) {
            vestedAmount = totalVested;
        } else {
            // Linear vesting after cliff
            vestedAmount = (totalVested * elapsed) / VESTING_PERIOD;
        }

        return vestedAmount - claimedCuts[founder];
    }

    /**
     * @notice Claim vested founder cuts
     */
    function claimVestedCuts() external nonReentrant {
        require(msg.sender == founderWallet, "Only founder can claim");

        uint256 claimable = getClaimableVested(msg.sender);
        require(claimable > 0, "Nothing to claim");
        require(address(this).balance >= claimable, "Insufficient treasury balance");

        claimedCuts[msg.sender] += claimable;

        (bool success, ) = payable(msg.sender).call{value: claimable}("");
        require(success, "Transfer failed");

        uint256 remaining = vestedCuts[msg.sender] - claimedCuts[msg.sender];
        emit VestedCutClaimed(msg.sender, claimable, remaining);
    }

    /**
     * @notice Get vesting info for founder
     * @param founder Founder address
     */
    function getVestingInfo(address founder) external view returns (
        uint256 totalVested,
        uint256 claimed,
        uint256 claimable,
        uint256 vestingStartTime,
        uint256 vestingEndTime
    ) {
        return (
            vestedCuts[founder],
            claimedCuts[founder],
            getClaimableVested(founder),
            vestingStart[founder],
            vestingStart[founder] + VESTING_PERIOD
        );
    }

    // ============ Relayer Reimbursement Functions ============

    /**
     * @notice Fund the relayer reimbursement pool for gasless voting
     */
    function fundReimbursementPool() external payable {
        relayerReimbursementPool += msg.value;
        emit ReimbursementPoolFunded(msg.value, relayerReimbursementPool);
    }

    /**
     * @notice Reimburse a relayer for gasless voting transaction
     * @dev Called by Governance contract after processing gasless vote
     * @param relayer Relayer address to reimburse
     * @param gasUsed Approximate gas used for the transaction
     */
    function reimburseRelayer(address relayer, uint256 gasUsed) external onlyRole(EXECUTOR_ROLE) {
        uint256 reimbursement = gasUsed * tx.gasprice;

        // Cap at max reimbursement
        if (reimbursement > maxReimbursementPerTx) {
            reimbursement = maxReimbursementPerTx;
        }

        // Cap at available pool
        if (reimbursement > relayerReimbursementPool) {
            reimbursement = relayerReimbursementPool;
        }

        if (reimbursement > 0) {
            relayerReimbursementPool -= reimbursement;
            relayerReimbursements[relayer] += reimbursement;

            (bool success, ) = payable(relayer).call{value: reimbursement}("");
            require(success, "Reimbursement failed");

            emit RelayerReimbursed(relayer, reimbursement, relayerReimbursementPool);
        }
    }

    /**
     * @notice Update max reimbursement per transaction
     * @param newMax New maximum in wei
     */
    function setMaxReimbursement(uint256 newMax) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(newMax <= 0.1 ether, "Max too high");
        uint256 oldMax = maxReimbursementPerTx;
        maxReimbursementPerTx = newMax;
        emit MaxReimbursementUpdated(oldMax, newMax);
    }

    /**
     * @notice Get reimbursement pool info
     */
    function getReimbursementPoolInfo() external view returns (
        uint256 poolBalance,
        uint256 maxPerTx
    ) {
        return (relayerReimbursementPool, maxReimbursementPerTx);
    }
}

